  1→import { useRef, useCallback } from 'react';
  2→import { getStarColor, getStarRadius, simpleHash } from '../utils/starUtils';
  3→
  4→// ── Constants ──────────────────────────────────────────────────────────
  5→const MAX_SPEED = 12;
  6→const ACCEL = 0.25;
  7→const BRAKE = 0.15;
  8→const FRICTION = 0.985;
  9→const YAW_RATE = 0.035;
 10→const PITCH_RATE = 0.025;
 11→const PITCH_MAX = (89 * Math.PI) / 180; // 89° in radians
 12→const MIN_VIEW_Z = 0.5;
 13→const SPAWN_DIST = 800;
 14→const RECYCLE_Z = 1200;
 15→const SORT_INTERVAL = 5;
 16→const TARGET_DIST_MAX = 150;
 17→const TARGET_Z_MIN = 2;
 18→const TWO_PI = Math.PI * 2;
 19→
 20→// ── Docking constants ─────────────────────────────────────────────────
 21→const DOCKING_THRESHOLD_Z = 18;
 22→const DOCKING_CENTER_MAX = 50;
 23→const MAGNET_THRESHOLD_Z = 80;
 24→const MAGNET_STRENGTH = 0.015;
 25→const DOCK_ACCEL = 0.5;
 26→const DOCK_MAX_SPEED = 8;
 27→
 28→/** Max viewZ at which labels start fading in */
 29→export const LABEL_Z_MAX = 800;
 30→
 31→/** Export docking thresholds for external use */
 32→export { MAGNET_THRESHOLD_Z };
 33→
 34→/** Parse "#5f92ff" → { r, g, b } */
 35→const parseHex = (hex) => ({
 36→    r: parseInt(hex.slice(1, 3), 16),
 37→    g: parseInt(hex.slice(3, 5), 16),
 38→    b: parseInt(hex.slice(5, 7), 16),
 39→});
 40→
 41→/** Seeded pseudo-random from integer seed */
 42→const seededRandom = (seed) => {
 43→    let s = seed | 0;
 44→    return () => {
 45→        s = (s * 1664525 + 1013904223) | 0;
 46→        return ((s >>> 0) / 4294967296);
 47→    };
 48→};
 49→
 50→/** Get forward direction vector from yaw + pitch */
 51→const getForwardVector = (yaw, pitch) => ({
 52→    x: Math.sin(yaw) * Math.cos(pitch),
 53→    y: Math.sin(pitch),
 54→    z: Math.cos(yaw) * Math.cos(pitch),
 55→});
 56→
 57→const useRocketMode = () => {
 58→    const isActiveRef = useRef(false);
 59→    const camPosRef = useRef({ x: 0, y: 0, z: 0 });
 60→    const yawRef = useRef(0);
 61→    const pitchRef = useRef(0);
 62→    const velocityRef = useRef(0);
 63→    const starsRef = useRef([]);
 64→    const sortedIndicesRef = useRef([]);
 65→    const keysRef = useRef({ w: false, s: false, a: false, d: false, q: false, e: false });
 66→    const targetIndexRef = useRef(-1);
 67→    const frameRef = useRef(0);
 68→    const layerRef = useRef(null);
 69→    const rafRef = useRef(null);
 70→    const stageSizeRef = useRef({ width: 0, height: 0 });
 71→
 72→    // ── Docking refs ──────────────────────────────────────────────────
 73→    const dockingStateRef = useRef('none'); // 'none' | 'magnet' | 'approaching' | 'flash' | 'done'
 74→    const dockingTargetIdxRef = useRef(-1);
 75→    const dockingProgressRef = useRef(0);
 76→    const dockingStartTimeRef = useRef(0);
 77→    const dockingCallbackRef = useRef(null);
 78→    const inputFrozenRef = useRef(false);
 79→    const dockingStarScaleRef = useRef(1);
 80→
 81→    const sortStars = useCallback(() => {
 82→        const stars = starsRef.current;
 83→        const indices = sortedIndicesRef.current;
 84→        // Insertion sort — fast for nearly-sorted arrays, sort by viewZ descending (far first)
 85→        for (let i = 1; i < indices.length; i++) {
 86→            const key = indices[i];
 87→            let j = i - 1;
 88→            while (j >= 0 && stars[indices[j]].viewZ < stars[key].viewZ) {
 89→                indices[j + 1] = indices[j];
 90→                j--;
 91→            }
 92→            indices[j + 1] = key;
 93→        }
 94→    }, []);
 95→
 96→    const tick = useCallback(() => {
 97→        if (!isActiveRef.current) return;
 98→
 99→        const keys = keysRef.current;
100→        const cam = camPosRef.current;
101→        const stars = starsRef.current;
102→        const size = stageSizeRef.current;
103→        const dockState = dockingStateRef.current;
104→
105→        // ── Input processing (frozen during docking) ──────────────────
106→        if (!inputFrozenRef.current) {
107→            // ── Yaw (A/D) ─────────────────────────────────────────────
108→            if (keys.a) yawRef.current -= YAW_RATE;
109→            if (keys.d) yawRef.current += YAW_RATE;
110→
111→            // ── Pitch (Q/E), clamped ──────────────────────────────────
112→            if (keys.q) pitchRef.current = Math.min(pitchRef.current + PITCH_RATE, PITCH_MAX);
113→            if (keys.e) pitchRef.current = Math.max(pitchRef.current - PITCH_RATE, -PITCH_MAX);
114→
115→            // ── Velocity ──────────────────────────────────────────────
116→            if (keys.w) {
117→                velocityRef.current = Math.min(velocityRef.current + ACCEL, MAX_SPEED);
118→            } else if (keys.s) {
119→                velocityRef.current = Math.max(velocityRef.current - BRAKE, 0);
120→            } else {
121→                velocityRef.current *= FRICTION;
122→                if (velocityRef.current < 0.01) velocityRef.current = 0;
123→            }
124→        }
125→
126→        // ── Magnetic pull (auto-aim toward docking target) ────────────
127→        if (dockState === 'magnet') {
128→            const tidx = dockingTargetIdxRef.current;
129→            if (tidx >= 0 && tidx < stars.length) {
130→                const target = stars[tidx];
131→                const relX = target.worldX - cam.x;
132→                const relY = target.worldY - cam.y;
133→                const relZ = target.worldZ - cam.z;
134→                const dist3D = Math.sqrt(relX * relX + relY * relY + relZ * relZ);
135→                if (dist3D > 0.01) {
136→                    const desiredYaw = Math.atan2(relX, relZ);
137→                    const desiredPitch = Math.asin(Math.max(-1, Math.min(1, relY / dist3D)));
138→                    // Proximity factor: 0 at MAGNET_THRESHOLD_Z, 1 at DOCKING_THRESHOLD_Z
139→                    const proximityFactor = Math.max(0, Math.min(1,
140→                        (MAGNET_THRESHOLD_Z - target.viewZ) / (MAGNET_THRESHOLD_Z - DOCKING_THRESHOLD_Z)
141→                    ));
142→                    const lerpFactor = MAGNET_STRENGTH * (0.3 + proximityFactor * 0.7);
143→                    // Normalize yaw difference to [-PI, PI]
144→                    let yawDiff = desiredYaw - yawRef.current;
145→                    while (yawDiff > Math.PI) yawDiff -= TWO_PI;
146→                    while (yawDiff < -Math.PI) yawDiff += TWO_PI;
147→                    yawRef.current += yawDiff * lerpFactor;
148→                    pitchRef.current += (desiredPitch - pitchRef.current) * lerpFactor;
149→                    pitchRef.current = Math.max(-PITCH_MAX, Math.min(PITCH_MAX, pitchRef.current));
150→                }
151→                // Disengage if target drifts beyond magnet zone
152→                if (target.viewZ > MAGNET_THRESHOLD_Z * 1.2 || target.viewZ < TARGET_Z_MIN) {
153→                    dockingStateRef.current = 'none';
154→                    dockingTargetIdxRef.current = -1;
155→                }
156→            }
157→        }
158→
159→        // ── Docking animation sequence ────────────────────────────────
160→        if (dockState === 'approaching' || dockState === 'flash') {
161→            const elapsed = performance.now() - dockingStartTimeRef.current;
162→            const tidx = dockingTargetIdxRef.current;
163→            const target = tidx >= 0 && tidx < stars.length ? stars[tidx] : null;
164→
165→            if (elapsed < 800 && target) {
166→                // Phase 1: Auto-approach (0-800ms)
167→                const relX = target.worldX - cam.x;
168→                const relY = target.worldY - cam.y;
169→                const relZ = target.worldZ - cam.z;
170→                const dist3D = Math.sqrt(relX * relX + relY * relY + relZ * relZ);
171→                if (dist3D > 0.01) {
172→                    const desiredYaw = Math.atan2(relX, relZ);
173→                    const desiredPitch = Math.asin(Math.max(-1, Math.min(1, relY / dist3D)));
174→                    let yawDiff = desiredYaw - yawRef.current;
175→                    while (yawDiff > Math.PI) yawDiff -= TWO_PI;
176→                    while (yawDiff < -Math.PI) yawDiff += TWO_PI;
177→                    yawRef.current += yawDiff * 0.12;
178→                    pitchRef.current += (desiredPitch - pitchRef.current) * 0.12;
179→                    pitchRef.current = Math.max(-PITCH_MAX, Math.min(PITCH_MAX, pitchRef.current));
180→                }
181→                velocityRef.current = Math.min(velocityRef.current + DOCK_ACCEL, DOCK_MAX_SPEED);
182→                // Quadratic ease-in scale: 1 → 9
183→                const t1 = elapsed / 800;
184→                dockingStarScaleRef.current = 1 + 8 * t1 * t1;
185→                dockingProgressRef.current = t1 * 0.6;
186→            } else if (elapsed < 1200 && target) {
187→                // Phase 2: Star explosion (800-1200ms)
188→                velocityRef.current *= 0.9;
189→                const t2 = (elapsed - 800) / 400;
190→                // Ease-out scale: 9 → 50
191→                const easeOut = 1 - (1 - t2) * (1 - t2);
192→                dockingStarScaleRef.current = 9 + 41 * easeOut;
193→                dockingProgressRef.current = 0.6 + t2 * 0.3;
194→            } else if (elapsed < 1700) {
195→                // Phase 3: White flash (1200-1700ms)
196→                velocityRef.current = 0;
197→                dockingStateRef.current = 'flash';
198→                const t3 = (elapsed - 1200) / 500;
199→                dockingProgressRef.current = 0.9 + t3 * 0.1;
200→            } else {
201→                // Done — trigger callback
202→                dockingStateRef.current = 'done';
203→                dockingProgressRef.current = 1;
204→                if (dockingCallbackRef.current) {
205→                    dockingCallbackRef.current();
206→                }
207→            }
208→        }
209→
210→        const yaw = yawRef.current;
211→        const pitch = pitchRef.current;
212→        const velocity = velocityRef.current;
213→
214→        // ── Position (move along forward vector) ─────────────────────
215→        const fwd = getForwardVector(yaw, pitch);
216→        cam.x += fwd.x * velocity;
217→        cam.y += fwd.y * velocity;
218→        cam.z += fwd.z * velocity;
219→
220→        // ── Pre-compute trig for view transform ──────────────────────
221→        const cosYaw = Math.cos(-yaw);
222→        const sinYaw = Math.sin(-yaw);
223→        const cosPitch = Math.cos(pitch);
224→        const sinPitch = Math.sin(pitch);
225→
226→        // ── View transform + recycling ───────────────────────────────
227→        const dockingActive = dockState !== 'none';
228→        const protectedIdx = dockingTargetIdxRef.current;
229→        for (let i = 0; i < stars.length; i++) {
230→            const star = stars[i];
231→
232→            // Translate to camera-relative
233→            const relX = star.worldX - cam.x;
234→            const relY = star.worldY - cam.y;
235→            const relZ = star.worldZ - cam.z;
236→
237→            // Yaw rotation (around Y axis)
238→            const rotX1 = relX * cosYaw + relZ * sinYaw;
239→            const rotZ1 = -relX * sinYaw + relZ * cosYaw;
240→
241→            // Pitch rotation (around X axis)
242→            const rotY2 = relY * cosPitch - rotZ1 * sinPitch;
243→            const viewZ = relY * sinPitch + rotZ1 * cosPitch;
244→
245→            // Cache on star for renderer
246→            star._rotX1 = rotX1;
247→            star._rotY2 = rotY2;
248→            star.viewZ = viewZ;
249→
250→            // Recycle stars that are behind camera or too far
251→            // Skip recycling for the docking target star
252→            if ((viewZ < MIN_VIEW_Z || viewZ > RECYCLE_Z) && !(dockingActive && i === protectedIdx)) {
253→                // Respawn ahead of camera using forward vector + random spread
254→                const dist = SPAWN_DIST * (0.5 + Math.random() * 0.5);
255→                const spreadX = (Math.random() - 0.5) * 2000;
256→                const spreadY = (Math.random() - 0.5) * 2000;
257→                star.worldX = cam.x + fwd.x * dist + spreadX;
258→                star.worldY = cam.y + fwd.y * dist + spreadY;
259→                star.worldZ = cam.z + fwd.z * dist + (Math.random() - 0.5) * 1000;
260→
261→                // Recompute view-space for the recycled position
262→                const rX = star.worldX - cam.x;
263→                const rY = star.worldY - cam.y;
264→                const rZ = star.worldZ - cam.z;
265→                const rX1 = rX * cosYaw + rZ * sinYaw;
266→                const rZ1 = -rX * sinYaw + rZ * cosYaw;
267→                star._rotX1 = rX1;
268→                star._rotY2 = rY * cosPitch - rZ1 * sinPitch;
269→                star.viewZ = rY * sinPitch + rZ1 * cosPitch;
270→            }
271→        }
272→
273→        // ── Sort (every N frames) ────────────────────────────────────
274→        frameRef.current++;
275→        if (frameRef.current % SORT_INTERVAL === 0) {
276→            sortStars();
277→        }
278→
279→        // ── Target detection ─────────────────────────────────────────
280→        const cx = size.width / 2;
281→        const cy = size.height / 2;
282→        const focalLength = size.width * 0.6;
283→        let bestIdx = -1;
284→        let bestDist = TARGET_DIST_MAX;
285→
286→        for (let i = 0; i < stars.length; i++) {
287→            const star = stars[i];
288→            if (star.viewZ < TARGET_Z_MIN) continue;
289→            const projX = cx + (star._rotX1 / star.viewZ) * focalLength;
290→            const projY = cy - (star._rotY2 / star.viewZ) * focalLength;
291→            const dx = projX - cx;
292→            const dy = projY - cy;
293→            const dist = Math.sqrt(dx * dx + dy * dy);
294→            if (dist < bestDist) {
295→                bestDist = dist;
296→                bestIdx = i;
297→            }
298→        }
299→        targetIndexRef.current = bestIdx;
300→
301→        // ── Docking detection ─────────────────────────────────────────
302→        if (dockState === 'none' && bestIdx >= 0) {
303→            const targetStar = stars[bestIdx];
304→            const viewZ = targetStar.viewZ;
305→            if (viewZ < DOCKING_THRESHOLD_Z && bestDist < DOCKING_CENTER_MAX) {
306→                // Close enough and centered — auto-dock
307→                dockingStateRef.current = 'approaching';
308→                dockingTargetIdxRef.current = bestIdx;
309→                dockingStartTimeRef.current = performance.now();
310→                dockingProgressRef.current = 0;
311→                dockingStarScaleRef.current = 1;
312→                inputFrozenRef.current = true;
313→            } else if (viewZ < MAGNET_THRESHOLD_Z && viewZ > DOCKING_THRESHOLD_Z) {
314→                // In magnet zone — engage gentle pull
315→                dockingStateRef.current = 'magnet';
316→                dockingTargetIdxRef.current = bestIdx;
317→            }
318→        }
319→        // Disengage magnet if best target changes
320→        if (dockState === 'magnet' && bestIdx !== dockingTargetIdxRef.current) {
321→            dockingStateRef.current = 'none';
322→            dockingTargetIdxRef.current = -1;
323→        }
324→
325→        // ── Redraw ───────────────────────────────────────────────────
326→        if (layerRef.current) {
327→            layerRef.current.batchDraw();
328→        }
329→
330→        rafRef.current = requestAnimationFrame(tick);
331→    }, [sortStars]);
332→
333→    const enter = useCallback((galaxyPosts, galaxyCenter, stageSize) => {
334→        stageSizeRef.current = stageSize;
335→        camPosRef.current = { x: galaxyCenter.x, y: galaxyCenter.y, z: 0 };
336→        yawRef.current = 0;
337→        pitchRef.current = 0;
338→        velocityRef.current = 0;
339→        frameRef.current = 0;
340→        targetIndexRef.current = -1;
341→
342→        // Reset docking state
343→        dockingStateRef.current = 'none';
344→        dockingTargetIdxRef.current = -1;
345→        dockingProgressRef.current = 0;
346→        dockingStarScaleRef.current = 1;
347→        inputFrozenRef.current = false;
348→
349→        // Build star array from posts — distributed in 3D volume
350→        const stars = [];
351→        for (let i = 0; i < galaxyPosts.length; i++) {
352→            const post = galaxyPosts[i];
353→            const uid = post.users?.id ?? post.user_id;
354→            const likeCount = post.like_count != null
355→                ? post.like_count
356→                : (Array.isArray(post.likes) && post.likes[0]?.count != null
357→                    ? post.likes[0].count : 0);
358→            const color = getStarColor(uid);
359→            const rng = seededRandom(simpleHash(post.id || String(i)));
360→            stars.push({
361→                postId: post.id,
362→                worldX: post.universe_x ?? post.display_x ?? galaxyCenter.x + (rng() - 0.5) * 2000,
363→                worldY: post.universe_y ?? post.display_y ?? galaxyCenter.y + (rng() - 0.5) * 2000,
364→                worldZ: (rng() - 0.5) * SPAWN_DIST * 2, // ±SPAWN_DIST from camera z=0
365→                viewZ: 0,
366→                _rotX1: 0,
367→                _rotY2: 0,
368→                color,
369→                colorRgb: parseHex(color),
370→                radius: getStarRadius(likeCount),
371→                title: post.title || 'Untitled',
372→                authorName: post.users?.name || post.user_name || 'Anonymous',
373→                post,
374→            });
375→        }
376→
377→        starsRef.current = stars;
378→
379→        // Build sorted indices (far → near by viewZ, will be sorted properly on first tick)
380→        const indices = new Array(stars.length);
381→        for (let i = 0; i < stars.length; i++) indices[i] = i;
382→        sortedIndicesRef.current = indices;
383→
384→        // Key listeners
385→        const onKeyDown = (e) => {
386→            const key = e.key.toLowerCase();
387→            if (key === 'w') keysRef.current.w = true;
388→            if (key === 's') keysRef.current.s = true;
389→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = true;
390→            if (key === 'd' || key === 'arrowright') keysRef.current.d = true;
391→            if (key === 'q' || key === 'arrowup') keysRef.current.q = true;
392→            if (key === 'e' || key === 'arrowdown') keysRef.current.e = true;
393→        };
394→        const onKeyUp = (e) => {
395→            const key = e.key.toLowerCase();
396→            if (key === 'w') keysRef.current.w = false;
397→            if (key === 's') keysRef.current.s = false;
398→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = false;
399→            if (key === 'd' || key === 'arrowright') keysRef.current.d = false;
400→            if (key === 'q' || key === 'arrowup') keysRef.current.q = false;
401→            if (key === 'e' || key === 'arrowdown') keysRef.current.e = false;
402→        };
403→
404→        window.addEventListener('keydown', onKeyDown);
405→        window.addEventListener('keyup', onKeyUp);
406→
407→        // Reset keys
408→        keysRef.current = { w: false, s: false, a: false, d: false, q: false, e: false };
409→        isActiveRef.current = true;
410→
411→        // Store listener refs for cleanup
412→        camPosRef.current._onKeyDown = onKeyDown;
413→        camPosRef.current._onKeyUp = onKeyUp;
414→
415→        // Start rAF
416→        rafRef.current = requestAnimationFrame(tick);
417→    }, [tick]);
418→
419→    const exit = useCallback(() => {
420→        isActiveRef.current = false;
421→        if (rafRef.current) {
422→            cancelAnimationFrame(rafRef.current);
423→            rafRef.current = null;
424→        }
425→        // Remove key listeners
426→        const cam = camPosRef.current;
427→        if (cam._onKeyDown) {
428→            window.removeEventListener('keydown', cam._onKeyDown);
429→            window.removeEventListener('keyup', cam._onKeyUp);
430→            delete cam._onKeyDown;
431→            delete cam._onKeyUp;
432→        }
433→        keysRef.current = { w: false, s: false, a: false, d: false, q: false, e: false };
434→        // Reset docking
435→        dockingStateRef.current = 'none';
436→        dockingTargetIdxRef.current = -1;
437→        dockingProgressRef.current = 0;
438→        dockingStarScaleRef.current = 1;
439→        inputFrozenRef.current = false;
440→    }, []);
441→
442→    const project = useCallback((star, cx, cy) => {
443→        if (star.viewZ <= MIN_VIEW_Z) return null; // behind camera
444→
445→        const stageWidth = stageSizeRef.current.width;
446→        const focalLength = stageWidth * 0.6; // ~80° FOV
447→        const projX = cx + (star._rotX1 / star.viewZ) * focalLength;
448→        const projY = cy - (star._rotY2 / star.viewZ) * focalLength; // negate Y for screen coords
449→        const scale = focalLength / star.viewZ;
450→
451→        return { projX, projY, scale };
452→    }, []);
453→
454→    const getTargetedPost = useCallback(() => {
455→        const idx = targetIndexRef.current;
456→        if (idx < 0 || idx >= starsRef.current.length) return null;
457→        return starsRef.current[idx].post;
458→    }, []);
459→
460→    const getSpeedRatio = useCallback(() => {
461→        return velocityRef.current / MAX_SPEED;
462→    }, []);
463→
464→    const getDockingState = useCallback(() => {
465→        return dockingStateRef.current;
466→    }, []);
467→
468→    const getSessionSnapshot = useCallback(() => {
469→        const cam = camPosRef.current;
470→        return {
471→            camX: cam.x,
472→            camY: cam.y,
473→            camZ: cam.z,
474→            yaw: yawRef.current,
475→            pitch: pitchRef.current,
476→            velocity: velocityRef.current,
477→            timestamp: Date.now(),
478→        };
479→    }, []);
480→
481→    const restoreFromSnapshot = useCallback((snapshot, galaxyPosts, stageSize) => {
482→        stageSizeRef.current = stageSize;
483→        camPosRef.current = { x: snapshot.camX, y: snapshot.camY, z: snapshot.camZ };
484→        yawRef.current = snapshot.yaw;
485→        pitchRef.current = snapshot.pitch;
486→        velocityRef.current = 0; // smooth re-entry
487→        frameRef.current = 0;
488→        targetIndexRef.current = -1;
489→
490→        // Reset docking state
491→        dockingStateRef.current = 'none';
492→        dockingTargetIdxRef.current = -1;
493→        dockingProgressRef.current = 0;
494→        dockingStarScaleRef.current = 1;
495→        inputFrozenRef.current = false;
496→
497→        // Build star array (same logic as enter)
498→        const galaxyCenter = { x: snapshot.camX, y: snapshot.camY };
499→        const stars = [];
500→        for (let i = 0; i < galaxyPosts.length; i++) {
501→            const post = galaxyPosts[i];
502→            const uid = post.users?.id ?? post.user_id;
503→            const likeCount = post.like_count != null
504→                ? post.like_count
505→                : (Array.isArray(post.likes) && post.likes[0]?.count != null
506→                    ? post.likes[0].count : 0);
507→            const color = getStarColor(uid);
508→            const rng = seededRandom(simpleHash(post.id || String(i)));
509→            stars.push({
510→                postId: post.id,
511→                worldX: post.universe_x ?? post.display_x ?? galaxyCenter.x + (rng() - 0.5) * 2000,
512→                worldY: post.universe_y ?? post.display_y ?? galaxyCenter.y + (rng() - 0.5) * 2000,
513→                worldZ: (rng() - 0.5) * SPAWN_DIST * 2,
514→                viewZ: 0,
515→                _rotX1: 0,
516→                _rotY2: 0,
517→                color,
518→                colorRgb: parseHex(color),
519→                radius: getStarRadius(likeCount),
520→                title: post.title || 'Untitled',
521→                authorName: post.users?.name || post.user_name || 'Anonymous',
522→                post,
523→            });
524→        }
525→
526→        starsRef.current = stars;
527→
528→        const indices = new Array(stars.length);
529→        for (let i = 0; i < stars.length; i++) indices[i] = i;
530→        sortedIndicesRef.current = indices;
531→
532→        // Key listeners
533→        const onKeyDown = (e) => {
534→            const key = e.key.toLowerCase();
535→            if (key === 'w') keysRef.current.w = true;
536→            if (key === 's') keysRef.current.s = true;
537→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = true;
538→            if (key === 'd' || key === 'arrowright') keysRef.current.d = true;
539→            if (key === 'q' || key === 'arrowup') keysRef.current.q = true;
540→            if (key === 'e' || key === 'arrowdown') keysRef.current.e = true;
541→        };
542→        const onKeyUp = (e) => {
543→            const key = e.key.toLowerCase();
544→            if (key === 'w') keysRef.current.w = false;
545→            if (key === 's') keysRef.current.s = false;
546→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = false;
547→            if (key === 'd' || key === 'arrowright') keysRef.current.d = false;
548→            if (key === 'q' || key === 'arrowup') keysRef.current.q = false;
549→            if (key === 'e' || key === 'arrowdown') keysRef.current.e = false;
550→        };
551→
552→        window.addEventListener('keydown', onKeyDown);
553→        window.addEventListener('keyup', onKeyUp);
554→
555→        keysRef.current = { w: false, s: false, a: false, d: false, q: false, e: false };
556→        isActiveRef.current = true;
557→
558→        camPosRef.current._onKeyDown = onKeyDown;
559→        camPosRef.current._onKeyUp = onKeyUp;
560→
561→        rafRef.current = requestAnimationFrame(tick);
562→    }, [tick]);
563→
564→    const setDockingCallback = useCallback((cb) => {
565→        dockingCallbackRef.current = cb;
566→    }, []);
567→
568→    const abortDocking = useCallback(() => {
569→        if (dockingStateRef.current === 'magnet') {
570→            dockingStateRef.current = 'none';
571→            dockingTargetIdxRef.current = -1;
572→            dockingProgressRef.current = 0;
573→            dockingStarScaleRef.current = 1;
574→        }
575→        // Approaching/flash are non-interruptible
576→    }, []);
577→
578→    const triggerDocking = useCallback((targetIdx, callback) => {
579→        if (dockingStateRef.current !== 'none' && dockingStateRef.current !== 'magnet') return;
580→        dockingStateRef.current = 'approaching';
581→        dockingTargetIdxRef.current = targetIdx;
582→        dockingStartTimeRef.current = performance.now();
583→        dockingProgressRef.current = 0;
584→        dockingStarScaleRef.current = 1;
585→        inputFrozenRef.current = true;
586→        if (callback) dockingCallbackRef.current = callback;
587→    }, []);
588→
589→    return {
590→        enter,
591→        exit,
592→        layerRef,
593→        starsRef,
594→        sortedIndicesRef,
595→        rocketPos: camPosRef,
596→        heading: yawRef,
597→        pitch: pitchRef,
598→        velocity: velocityRef,
599→        targetIndexRef,
600→        stageSizeRef,
601→        project,
602→        isActive: isActiveRef,
603→        getTargetedPost,
604→        getSpeedRatio,
605→        // Docking API
606→        getDockingState,
607→        getSessionSnapshot,
608→        restoreFromSnapshot,
609→        setDockingCallback,
610→        abortDocking,
611→        triggerDocking,
612→        dockingStateRef,
613→        dockingTargetIdxRef,
614→        dockingProgressRef,
615→        dockingStarScaleRef,
616→        inputFrozenRef,
617→    };
