  4→const RocketHUD = ({ rocketMode, onExit, onInteract }) => {
  5→    const [speed, setSpeed] = useState(0);
  6→    const [pitch, setPitch] = useState(0);
  7→    const [targetInfo, setTargetInfo] = useState(null);
  8→    const [distance, setDistance] = useState(null);
  9→    const [dockingState, setDockingState] = useState('none');
 10→    const pollRef = useRef(null);
 11→
 12→    // Poll refs at 10 Hz for HUD display
 13→    useEffect(() => {
 14→        pollRef.current = setInterval(() => {
 15→            setSpeed(rocketMode.getSpeedRatio());
 16→            setDockingState(rocketMode.getDockingState());
 17→
 18→            // Read pitch in degrees
 19→            if (rocketMode.pitch) {
 20→                setPitch(Math.round((rocketMode.pitch.current * 180) / Math.PI));
 21→            }
 22→
 23→            const idx = rocketMode.targetIndexRef.current;
 24→            const stars = rocketMode.starsRef.current;
 25→            if (idx >= 0 && idx < stars.length) {
 26→                const star = stars[idx];
 27→                setTargetInfo({ title: star.title, author: star.authorName });
 28→                setDistance(Math.round(star.viewZ * 7));
 29→            } else {
 30→                setTargetInfo(null);
 31→                setDistance(null);
 32→            }
 33→        }, 100);
 34→
 35→        return () => {
 36→            if (pollRef.current) clearInterval(pollRef.current);
 37→        };
 38→    }, [rocketMode]);
 39→
 40→    // Key bindings for Enter/Space (interact) and Escape (exit)
 41→    const handleKey = useCallback((e) => {
 42→        const ds = rocketMode.getDockingState();
 43→
 44→        // Suppress all keys during approaching/flash (non-interruptible)
 45→        if (ds === 'approaching' || ds === 'flash') {
 46→            e.preventDefault();
 47→            return;
 48→        }
 49→
 50→        if (e.key === 'Enter' || e.key === ' ') {
 51→            e.preventDefault();
 52→            onInteract();
 53→        } else if (e.key === 'Escape') {
 54→            e.preventDefault();
 55→            // During magnet phase, abort docking instead of exiting
 56→            if (ds === 'magnet') {
 57→                rocketMode.abortDocking();
 58→            } else {
 59→                onExit();
 60→            }
 61→        }
 62→    }, [onInteract, onExit, rocketMode]);
 63→
 64→    useEffect(() => {
 65→        window.addEventListener('keydown', handleKey);
 66→        return () => window.removeEventListener('keydown', handleKey);
 67→    }, [handleKey]);
 68→
 69→    const absPitch = Math.abs(pitch);
 70→    const isDocking = dockingState === 'approaching' || dockingState === 'flash';
 71→
 72→    return (
 73→        <div className={styles.rocketHud}>
 74→            {/* Exit button */}
 75→            <button className={styles.rocketExitBtn} onClick={onExit} disabled={isDocking}>
 76→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="16" height="16" fill="currentColor">
 77→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
 78→                </svg>
 79→                Exit Rocket
 80→            </button>
 81→
 82→            {/* Pitch indicator (top-right, only when |pitch| > 5°) */}
 83→            {absPitch > 5 && (
 84→                <div className={styles.rocketPitch}>
 85→                    {pitch > 0 ? '\u2191' : '\u2193'} {absPitch}\u00B0
 86→                </div>
 87→            )}
 88→
 89→            {/* Target info (below center) */}
 90→            {targetInfo && (
 91→                <div className={styles.rocketTarget}>
 92→                    <div className={styles.rocketTargetTitle}>{targetInfo.title}</div>
 93→                    <div className={styles.rocketTargetAuthor}>by {targetInfo.author}</div>
 94→                    {distance != null && (
 95→                        <div className={styles.rocketTargetDistance}>{distance} LY</div>
 96→                    )}
 97→                    {isDocking ? (
 98→                        <div className={styles.rocketTargetDocking}>DOCKING...</div>
 99→                    ) : (
100→                        <div className={styles.rocketTargetPrompt}>Press ENTER to read</div>
101→                    )}
102→                </div>
103→            )}
104→
105→            {/* Speed bar */}
106→            <div className={styles.rocketSpeedBar}>
107→                <span className={styles.rocketSpeedLabel}>SPD</span>
108→                <div className={styles.rocketSpeedTrack}>
109→                    <div
110→                        className={styles.rocketSpeedFill}
111→                        style={{ width: `${Math.round(speed * 100)}%` }}
112→                    />
113→                </div>
114→                <span className={styles.rocketSpeedValue}>{Math.round(speed * 100)}%</span>
115→            </div>
116→
117→            {/* Controls hint */}
118→            <div className={styles.rocketControls}>
119→                <span>W/S Throttle</span>
120→                <span>A/D Yaw</span>
121→                <span>Q/E Pitch</span>
122→                <span>ENTER Read</span>
123→                <span>ESC Exit</span>
124→            </div>
125→        </div>
126→    );
127→};
