 664→            setReverseWarpActive(true);
 665→            pendingRocketRestoreRef.current = session;
 666→        } catch {
 667→            sessionStorage.removeItem('rocketSession');
 668→        }
 669→    }, []);
 670→
 671→    // Once posts load, restore rocket mode from session
 672→    useEffect(() => {
 673→        const session = pendingRocketRestoreRef.current;
 674→        if (!session || postArray.length === 0) return;
 675→
 676→        const galaxyPosts = postArray.filter(p => {
 677→            const uid = p.users?.id ?? p.user_id;
 678→            return uid === session.galaxyUserId;
 679→        });
 680→
 681→        if (galaxyPosts.length === 0) {
 682→            pendingRocketRestoreRef.current = null;
 683→            setReverseWarpActive(false);
 684→            return;
 685→        }
 686→
 687→        pendingRocketRestoreRef.current = null;
 688→        selectedGalaxyUserIdRef.current = session.galaxyUserId;
 689→        setUniverseMode('pilot');
 690→        rocketMode.restoreFromSnapshot(session, galaxyPosts, stageSize);
 691→
 692→        setTimeout(() => setReverseWarpActive(false), 600);
 693→    }, [postArray, rocketMode, stageSize]);
 694→
 695→    // One-time auto focus after first payload is loaded.
 696→    // Skip if we have a constellation flyTo target — that effect handles it instead.
 697→    useEffect(() => {
 698→        if (!userId) return;
 699→        if (isInitialLoading) return;
 700→        if (hasAutoFocusedOwnGalaxyRef.current) return;
 701→        if (constellationFlyToRef.current) return;
 702→
 703→        const ownGalaxy = galaxies.find((galaxy) => galaxy.userId === userId);
 704→        const target = ownGalaxy
 705→            ? { x: ownGalaxy.x, y: ownGalaxy.y }
 706→            : (centroidTargets.get(userId) || ownGalaxyTarget);
 707→
 708→        // Wait until we have a concrete own target; fallback is resolved asynchronously.
 709→        if (!target) return;
 710→
 711→        hasAutoFocusedOwnGalaxyRef.current = true;
 712→        flyTo(target.x, target.y, MIN_UNIVERSE_ZOOM);
 713→    }, [userId, isInitialLoading, galaxies, centroidTargets, ownGalaxyTarget, flyTo]);
 714→
 715→    // Fly to constellation midpoint when arriving from a notification link.
 716→    useEffect(() => {
 717→        const target = constellationFlyToRef.current;
 718→        if (!target) return;
 719→        if (isInitialLoading) return;
 720→
 721→        const posA = finalStarPositions.get(target.starIdA);
 722→        const posB = finalStarPositions.get(target.starIdB);
 723→        if (!posA || !posB) return;
 724→
 725→        constellationFlyToRef.current = null;
 726→        hasAutoFocusedOwnGalaxyRef.current = true;
 727→
 728→        const mx = (posA.x + posB.x) / 2;
 729→        const my = (posA.y + posB.y) / 2;
 730→        flyTo(mx, my, 1.0);
 731→
 732→        // Clear navigation state so refreshing doesn't re-trigger
 733→        navigate(location.pathname, { replace: true, state: {} });
 734→    }, [isInitialLoading, finalStarPositions, flyTo, navigate, location.pathname]);
 735→
 736→    const settledPayload = useMemo(() => {
 737→        if (!isSettled || activePosts.length === 0) return [];
 738→
 739→        const payload = [];
 740→        for (const post of activePosts) {
 741→            if (!post?.id) continue;
 742→            const pos = getComputedStarPosition(post);
 743→            if (!pos || !Number.isFinite(pos.x) || !Number.isFinite(pos.y)) continue;
 744→
 745→            payload.push({
 746→                post_id: post.id,
 747→                settled_x: Math.round(pos.x * 100) / 100,
 748→                settled_y: Math.round(pos.y * 100) / 100,
 749→            });
 750→        }
 751→
 752→        payload.sort((a, b) => String(a.post_id).localeCompare(String(b.post_id)));
 753→        return payload;
 754→    }, [activePosts, getComputedStarPosition, isSettled]);
 755→
 756→    // Placeholder persistence hook: debounced Supabase RPC for settled positions.
 757→    useEffect(() => {
 758→        if (!ENABLE_SETTLED_RPC_SAVE) return;
 759→        if (!isSettled || settledPayload.length === 0) return;
 760→
 761→        const signature = JSON.stringify(settledPayload);
 762→        if (signature === lastSettledPayloadRef.current) return;
 763→
 764→        if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
 765→        settleDebounceRef.current = setTimeout(async () => {
 766→            lastSettledPayloadRef.current = signature;
 767→            try {
 768→                const { error } = await supabase.rpc('save_universe_settled_positions', {
 769→                    positions_payload: settledPayload,
 770→                });
 771→                if (error) {
 772→                    console.warn('[universe] settle save placeholder RPC returned error:', error.message);
 773→                }
 774→            } catch (err) {
 775→                console.warn('[universe] settle save placeholder RPC failed:', err?.message || err);
 776→            }
 777→        }, 1200);
 778→
 779→        return () => {
 780→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
 781→        };
 782→    }, [isSettled, settledPayload]);
 783→
 784→    // ESC key to cancel link mode or dismiss constellation focus
 785→    useEffect(() => {
 786→        if (universeMode !== 'strategic') return;
 787→        if (!isLinkMode && !focusedConstellation) return;
 788→        const handleKeyDown = (e) => {
 789→            if (e.key === 'Escape') {
