 792→            }
 793→        };
 794→        window.addEventListener('keydown', handleKeyDown);
 795→        return () => window.removeEventListener('keydown', handleKeyDown);
 796→    }, [isLinkMode, cancelLinkMode, focusedConstellation, universeMode]);
 797→
 798→    useEffect(() => {
 799→        return () => {
 800→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
 801→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
 802→            rocketMode.exit();
 803→        };
 804→    }, []);
